URL validation alone is insufficient because attackers can bypass it using DNS rebinding attacks. The hostname resolves to a safe IP during validation, but then resolves to an internal IP (like 127.0.0.1 or cloud metadata endpoints) when the actual request is made.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const axios = require('axios');
const dns = require('dns').promises;
const { URL } = require('url');

const app = express();
app.use(express.json());

// VULNERABLE: DNS rebinding bypass
async function isInternalIP(hostname) {
  try {
    const addresses = await dns.lookup(hostname, { all: true });
    for (const addr of addresses) {
      if (addr.address.startsWith('127.') ||
          addr.address.startsWith('10.') ||
          addr.address.startsWith('192.168.') ||
          addr.address.startsWith('169.254.')) {
        return true;
      }
    }
    return false;
  } catch (e) {
    return true;
  }
}

app.post('/api/webhook/test', async (req, res) => {
  const { url } = req.body;

  try {
    const parsedUrl = new URL(url);

    // Check at validation time - DNS can change!
    if (await isInternalIP(parsedUrl.hostname)) {
      return res.status(403).json({ error: 'Internal IPs not allowed' });
    }

    // VULNERABLE: Time gap between DNS check and request
    // Attacker's DNS can rebind to internal IP here
    const response = await axios.get(url, { timeout: 5000 });
    res.json({ status: 'success', data: response.data });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

app.listen(3000);
```

**Attack Payload**:
```text
Attacker setup:
1. Configure DNS server for attacker.com with TTL=0
2. First DNS query returns: 1.2.3.4 (public IP - passes validation)
3. Second DNS query returns: 169.254.169.254 (AWS metadata - actual request)

Webhook URL: https://rebind.attacker.com/steal-aws-creds

The rebinding happens in milliseconds between validation and request.
```

**Why This Is Dangerous**:
- DNS resolution happens twice: once during validation, once during HTTP request
- Attacker controls DNS with TTL=0, forcing re-resolution
- AWS/GCP/Azure metadata endpoints expose IAM credentials
- Internal services (Redis, Elasticsearch, admin panels) become accessible

**SECURE VERSION**:

```javascript
const express = require('express');
const http = require('http');
const https = require('https');
const dns = require('dns').promises;
const { URL } = require('url');
const net = require('net');

const app = express();
app.use(express.json());

// Blocklist of internal IP ranges
const BLOCKED_IP_RANGES = [
  { start: '0.0.0.0', end: '0.255.255.255' },
  { start: '10.0.0.0', end: '10.255.255.255' },
  { start: '127.0.0.0', end: '127.255.255.255' },
  { start: '169.254.0.0', end: '169.254.255.255' },
  { start: '172.16.0.0', end: '172.31.255.255' },
  { start: '192.168.0.0', end: '192.168.255.255' },
];

function ipToInt(ip) {
  return ip.split('.').reduce((acc, octet) => (acc << 8) + parseInt(octet), 0) >>> 0;
}

function isBlockedIP(ip) {
  if (!net.isIPv4(ip)) return true; // Block non-IPv4 for simplicity
  const ipInt = ipToInt(ip);
  return BLOCKED_IP_RANGES.some(range => {
    const start = ipToInt(range.start);
    const end = ipToInt(range.end);
    return ipInt >= start && ipInt <= end;
  });
}

// SECURE: Custom agent that validates IP at connection time
function createSecureAgent(protocol) {
  const Agent = protocol === 'https:' ? https.Agent : http.Agent;

  return new Agent({
    lookup: (hostname, options, callback) => {
      dns.lookup(hostname, { all: true })
        .then(addresses => {
          // Validate ALL resolved IPs before connecting
          for (const addr of addresses) {
            if (isBlockedIP(addr.address)) {
              return callback(new Error(`Blocked IP: ${addr.address}`));
            }
          }
          // Return first valid address
          callback(null, addresses[0].address, addresses[0].family);
        })
        .catch(callback);
    }
  });
}

app.post('/api/webhook/test', async (req, res) => {
  const { url } = req.body;

  try {
    const parsedUrl = new URL(url);

    // Only allow HTTP/HTTPS
    if (!['http:', 'https:'].includes(parsedUrl.protocol)) {
      return res.status(400).json({ error: 'Only HTTP/HTTPS allowed' });
    }

    const agent = createSecureAgent(parsedUrl.protocol);
    const client = parsedUrl.protocol === 'https:' ? https : http;

    const response = await new Promise((resolve, reject) => {
      const request = client.get(parsedUrl.href, { 
        agent,
        timeout: 5000,
        headers: { 'User-Agent': 'WebhookBot/1.0' }
      }, resolve);
      request.on('error', reject);
      request.on('timeout', () => reject(new Error('Request timeout')));
    });

    let data = '';
    for await (const chunk of response) {
      data += chunk;
      if (data.length > 1024 * 1024) throw new Error('Response too large');
    }

    res.json({ status: 'success', statusCode: response.statusCode });
  } catch (error) {
    console.error(`Webhook error: ${error.message}`);
    res.status(400).json({ error: 'Request failed' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Custom DNS lookup in agent**: IP validation happens at connection time, not before, eliminating the rebinding window
- **Comprehensive IP blocklist**: Covers all private ranges including cloud metadata (169.254.x.x)
- **Protocol allowlist**: Only HTTP/HTTPS prevents file://, gopher://, dict:// attacks
- **Response size limit**: Prevents memory exhaustion from large responses

Excellent questions. IPv6, localhost subdomains (like localtest.me which resolves to 127.0.0.1), and redirects are common bypass techniques. Redirects are particularly dangerous because the server might redirect to an internal URL after passing initial validation.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const http = require('http');
const https = require('https');
const dns = require('dns').promises;
const { URL } = require('url');
const net = require('net');
const ipaddr = require('ipaddr.js');
const winston = require('winston');

const app = express();
app.use(express.json());

// Production logger
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'ssrf-audit.log' })
  ]
});

// Configuration
const CONFIG = {
  MAX_REDIRECTS: 3,
  TIMEOUT_MS: 10000,
  MAX_RESPONSE_SIZE: 5 * 1024 * 1024,
  ALLOWED_PORTS: [80, 443, 8080, 8443],
  BLOCKED_HOSTNAMES: ['metadata.google.internal', 'metadata.goog']
};

// Comprehensive IP validation supporting IPv4 and IPv6
function isBlockedIP(ip) {
  try {
    const addr = ipaddr.parse(ip);

    // Check IPv4
    if (addr.kind() === 'ipv4') {
      const ranges = [
        'unspecified',     // 0.0.0.0/8
        'broadcast',       // 255.255.255.255/32
        'multicast',       // 224.0.0.0/4
        'linkLocal',       // 169.254.0.0/16
        'loopback',        // 127.0.0.0/8
        'private',         // 10/8, 172.16/12, 192.168/16
        'reserved'         // Various reserved ranges
      ];
      return ranges.some(range => addr.range() === range);
    }

    // Check IPv6
    if (addr.kind() === 'ipv6') {
      // Block IPv6 loopback, link-local, private ranges
      const ranges = [
        'unspecified',     // ::
        'loopback',        // ::1
        'linkLocal',       // fe80::/10
        'uniqueLocal',     // fc00::/7
        'multicast'        // ff00::/8
      ];
      if (ranges.some(range => addr.range() === range)) return true;

      // Check for IPv4-mapped IPv6 (::ffff:127.0.0.1)
      if (addr.isIPv4MappedAddress()) {
        return isBlockedIP(addr.toIPv4Address().toString());
      }
    }

    return false;
  } catch (e) {
    return true; // Block unparseable addresses
  }
}

function isBlockedHostname(hostname) {
  const lower = hostname.toLowerCase();

  // Block cloud metadata hostnames
  if (CONFIG.BLOCKED_HOSTNAMES.some(h => lower.includes(h))) return true;

  // Block localhost variations
  if (lower === 'localhost' || lower.endsWith('.localhost')) return true;

  // Block common DNS rebinding domains
  const rebindingDomains = ['localtest.me', 'lvh.me', 'vcap.me', 'nip.io', 'xip.io', 'sslip.io'];
  if (rebindingDomains.some(d => lower.endsWith(d))) return true;

  return false;
}

function validatePort(port, protocol) {
  const defaultPort = protocol === 'https:' ? 443 : 80;
  const actualPort = port ? parseInt(port) : defaultPort;
  return CONFIG.ALLOWED_PORTS.includes(actualPort);
}

// Create agent with DNS validation at connection time
function createSecureAgent(protocol) {
  const Agent = protocol === 'https:' ? https.Agent : http.Agent;

  return new Agent({
    keepAlive: false,
    lookup: (hostname, options, callback) => {
      // First check hostname blocklist
      if (isBlockedHostname(hostname)) {
        return callback(new Error(`Blocked hostname: ${hostname}`));
      }

      dns.lookup(hostname, { all: true, family: 0 }) // 0 = both IPv4 and IPv6
        .then(addresses => {
          if (addresses.length === 0) {
            return callback(new Error('No addresses found'));
          }

          // Validate ALL resolved IPs
          for (const addr of addresses) {
            if (isBlockedIP(addr.address)) {
              logger.warn('Blocked IP access attempt', {
                hostname,
                ip: addr.address,
                timestamp: new Date().toISOString()
              });
              return callback(new Error(`Blocked IP: ${addr.address}`));
            }
          }

          callback(null, addresses[0].address, addresses[0].family);
        })
        .catch(err => callback(err));
    }
  });
}

// Safe URL fetcher with redirect handling
async function safeFetch(urlString, redirectCount = 0, requestId) {
  if (redirectCount > CONFIG.MAX_REDIRECTS) {
    throw new Error('Too many redirects');
  }

  const parsedUrl = new URL(urlString);

  // Protocol validation
  if (!['http:', 'https:'].includes(parsedUrl.protocol)) {
    throw new Error(`Blocked protocol: ${parsedUrl.protocol}`);
  }

  // Port validation
  if (!validatePort(parsedUrl.port, parsedUrl.protocol)) {
    throw new Error(`Blocked port: ${parsedUrl.port || 'default'}`);
  }

  // Hostname validation (defense in depth)
  if (isBlockedHostname(parsedUrl.hostname)) {
    throw new Error(`Blocked hostname: ${parsedUrl.hostname}`);
  }

  const agent = createSecureAgent(parsedUrl.protocol);
  const client = parsedUrl.protocol === 'https:' ? https : http;

  return new Promise((resolve, reject) => {
    const request = client.get(parsedUrl.href, {
      agent,
      timeout: CONFIG.TIMEOUT_MS,
      headers: {
        'User-Agent': 'SecureWebhookBot/2.0',
        'Accept': 'application/json, text/plain, */*'
      }
    }, async (response) => {
      // Handle redirects with full validation
      if ([301, 302, 303, 307, 308].includes(response.statusCode)) {
        const location = response.headers.location;
        if (!location) {
          return reject(new Error('Redirect without location'));
        }

        // Resolve relative URLs
        const redirectUrl = new URL(location, urlString).href;

        logger.info('Following redirect', {
          requestId,
          from: urlString,
          to: redirectUrl,
          redirectCount: redirectCount + 1
        });

        try {
          // Recursively fetch with full validation on redirect target
          const result = await safeFetch(redirectUrl, redirectCount + 1, requestId);
          resolve(result);
        } catch (e) {
          reject(e);
        }
        return;
      }

      // Collect response with size limit
      let data = '';
      let size = 0;

      response.on('data', chunk => {
        size += chunk.length;
        if (size > CONFIG.MAX_RESPONSE_SIZE) {
          request.destroy();
          reject(new Error('Response too large'));
        }
        data += chunk;
      });

      response.on('end', () => {
        resolve({
          statusCode: response.statusCode,
          headers: response.headers,
          body: data,
          finalUrl: urlString
        });
      });
    });

    request.on('error', reject);
    request.on('timeout', () => {
      request.destroy();
      reject(new Error('Request timeout'));
    });
  });
}

// Rate limiting middleware
const rateLimit = require('express-rate-limit');
const webhookLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 10,
  message: { error: 'Too many requests' }
});

app.post('/api/webhook/test', webhookLimiter, async (req, res) => {
  const requestId = `req_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  const { url } = req.body;

  logger.info('Webhook request', {
    requestId,
    url,
    ip: req.ip,
    userAgent: req.get('User-Agent')
  });

  if (!url || typeof url !== 'string') {
    return res.status(400).json({ error: 'URL required' });
  }

  try {
    const result = await safeFetch(url, 0, requestId);

    logger.info('Webhook success', {
      requestId,
      statusCode: result.statusCode,
      finalUrl: result.finalUrl
    });

    res.json({
      requestId,
      status: 'success',
      statusCode: result.statusCode,
      contentType: result.headers['content-type']
    });
  } catch (error) {
    logger.warn('Webhook blocked/failed', {
      requestId,
      url,
      error: error.message
    });

    res.status(400).json({
      requestId,
      error: 'Request failed',
      reason: error.message.includes('Blocked') ? 'Blocked destination' : 'Request error'
    });
  }
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Hostname blocklist** (first layer):
