<?php
class SecureWebhookProcessor {
    private $allowedSchemes = ['https'];
    private $dnsCache = [];

    public function processWebhook($url) {
        $parsed = parse_url($url);

        if (!$parsed || !isset($parsed['host'])) {
            throw new Exception('Invalid URL format');
        }

        // Validate scheme - HTTPS only
        if (!in_array($parsed['scheme'] ?? '', $this->allowedSchemes)) {
            throw new Exception('Only HTTPS URLs allowed');
        }

        // Resolve DNS ONCE and pin the IP
        $resolvedIP = $this->resolveAndValidateIP($parsed['host']);

        // Build URL with resolved IP, preserving original host for SNI
        $ipBasedUrl = $this->buildIPBasedUrl($parsed, $resolvedIP);

        // Make request using resolved IP directly
        return $this->fetchWithPinnedIP($ipBasedUrl, $parsed['host'], $resolvedIP);
    }

    private function resolveAndValidateIP($hostname) {
        // Prevent DNS rebinding by resolving once and caching
        $records = dns_get_record($hostname, DNS_A | DNS_AAAA);

        if (empty($records)) {
            throw new Exception('Could not resolve hostname');
        }

        foreach ($records as $record) {
            $ip = $record['ip'] ?? $record['ipv6'] ?? null;
            if ($ip && $this->isInternalIP($ip)) {
                throw new Exception('Resolved IP is internal - request blocked');
            }
        }

        // Use first valid IP
        $ip = $records[0]['ip'] ?? $records[0]['ipv6'];

        // Double-check the resolved IP
        if ($this->isInternalIP($ip)) {
            throw new Exception('Internal IP detected');
        }

        return $ip;
    }

    private function fetchWithPinnedIP($url, $originalHost, $pinnedIP) {
        $ch = curl_init();

        // CRITICAL: Force connection to our resolved IP
        curl_setopt($ch, CURLOPT_RESOLVE, [
            "{$originalHost}:443:{$pinnedIP}",
            "{$originalHost}:80:{$pinnedIP}"
        ]);

        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_TIMEOUT, 10);
        curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, 5);

        // CRITICAL: Disable redirects to prevent redirect-based rebinding
        curl_setopt($ch, CURLOPT_FOLLOWLOCATION, false);
        curl_setopt($ch, CURLOPT_MAXREDIRS, 0);

        // Verify SSL certificate
        curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, true);
        curl_setopt($ch, CURLOPT_SSL_VERIFYHOST, 2);

        $response = curl_exec($ch);
        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        $effectiveUrl = curl_getinfo($ch, CURLINFO_EFFECTIVE_URL);

        curl_close($ch);

        // Log the request for monitoring
        error_log("Webhook request to {$pinnedIP} ({$originalHost}): HTTP {$httpCode}");

        return $response;
    }

    private function isInternalIP($ip) {
        // Comprehensive internal IP detection
        return filter_var($ip, FILTER_VALIDATE_IP, 
            FILTER_FLAG_NO_PRIV_RANGE | FILTER_FLAG_NO_RES_RANGE) === false;
    }

    private function buildIPBasedUrl($parsed, $ip) {
        $port = $parsed['port'] ?? ($parsed['scheme'] === 'https' ? 443 : 80);
        $path = $parsed['path'] ?? '/';
        $query = isset($parsed['query']) ? '?' . $parsed['query'] : '';

        return "{$parsed['scheme']}://{$parsed['host']}:{$port}{$path}{$query}";
    }
}
