        // Handle decimal IP notation (e.g., 2130706433 = 127.0.0.1)
        if (is_numeric($host) && $host > 0 && $host <= 4294967295) {
            return long2ip((int)$host);
        }

        // Handle octal notation (e.g., 0177.0.0.1 = 127.0.0.1)
        if (preg_match('/^0[0-7]+(\.0[0-7]+){3}$/', $host)) {
            $parts = explode('.', $host);
            $ip = implode('.', array_map(fn($p) => octdec($p), $parts));
