        // Handle hex notation (e.g., 0x7f.0x0.0x0.0x1 = 127.0.0.1)
        if (preg_match('/^0x[0-9a-f]+(\.0x[0-9a-f]+){3}$/i', $host)) {
            $parts = explode('.', $host);
            $ip = implode('.', array_map(fn($p) => hexdec($p), $parts));
