const BLOCKED_PORTS = [22, 23, 25, 445, 3306, 5432, 6379, 27017];

function isInternalIP(ip) {
  // Check for private, loopback, link-local, and special ranges
  const blocks = [
    /^127\./,                    // Loopback
    /^10\./,                     // Private Class A
    /^172\.(1[6-9]|2[0-9]|3[01])\./,  // Private Class B
    /^192\.168\./,               // Private Class C
    /^169\.254\./,               // Link-local
    /^0\./,                      // Current network
    /^100\.(6[4-9]|[7-9][0-9]|1[01][0-9]|12[0-7])\./,  // Carrier-grade NAT
    /^192\.0\.0\./,              // IETF Protocol Assignments
    /^192\.0\.2\./,              // TEST-NET-1
    /^198\.51\.100\./,           // TEST-NET-2
    /^203\.0\.113\./,            // TEST-NET-3
    /^224\./,                    // Multicast
    /^240\./,                    // Reserved
    /^255\.255\.255\.255$/,      // Broadcast
    /^::1$/,                     // IPv6 loopback
    /^fe80:/i,                   // IPv6 link-local
    /^fc00:/i,                   // IPv6 unique local
    /^fd00:/i                    // IPv6 unique local
  ];

  return blocks.some(pattern => pattern.test(ip));
}

function resolveAndValidate(hostname) {
  return new Promise((resolve, reject) => {
    // Force fresh DNS lookup
    dns.lookup(hostname, { all: true }, (err, addresses) => {
      if (err) return reject(new Error('DNS resolution failed'));

      // Validate ALL returned IPs
      for (const addr of addresses) {
        if (isInternalIP(addr.address)) {
          return reject(new Error('Internal IP addresses not allowed'));
        }
      }

      // Return the first valid IP to pin for the request
      resolve(addresses[0].address);
    });
  });
}

async function safeFetch(urlString) {
  const url = new URL(urlString);

  // Validate protocol
  if (!ALLOWED_PROTOCOLS.includes(url.protocol)) {
    throw new Error('Protocol not allowed');
  }

  // Validate port
  const port = url.port || (url.protocol === 'https:' ? 443 : 80);
  if (BLOCKED_PORTS.includes(parseInt(port))) {
    throw new Error('Port not allowed');
  }

  // Resolve DNS and get validated IP
  const resolvedIP = await resolveAndValidate(url.hostname);

  // KEY DEFENSE: Pin to resolved IP to prevent DNS rebinding
  return new Promise((resolve, reject) => {
    const options = {
      hostname: resolvedIP,  // Use IP directly, not hostname
      port: port,
      path: url.pathname + url.search,
      method: 'GET',
      timeout: 5000,
      headers: {
        'Host': url.hostname  // Preserve original Host header
      },
      // Double-check: Reject if socket connects to internal IP
      lookup: (hostname, options, callback) => {
        // Already resolved, just return our pinned IP
        callback(null, resolvedIP, net.isIPv6(resolvedIP) ? 6 : 4);
      }
    };

    const client = url.protocol === 'https:' ? https : http;
    const req = client.request(options, (res) => {
      // Validate response doesn't redirect to internal
      if (res.headers.location) {
        try {
          const redirectUrl = new URL(res.headers.location, urlString);
          // Would need to validate redirect target too
        } catch (e) {
          return reject(new Error('Invalid redirect'));
        }
      }

      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => resolve({ status: res.statusCode, data }));
    });

    req.on('error', reject);
    req.on('timeout', () => {
      req.destroy();
      reject(new Error('Request timeout'));
    });

    req.end();
  });
}

