// DNS cache to prevent cache poisoning attacks
class SecureDNSCache {
  constructor(maxAge, maxSize) {
    this.cache = new Map();
    this.maxAge = maxAge;
    this.maxSize = maxSize;
  }

  get(hostname) {
    const entry = this.cache.get(hostname);
    if (entry && Date.now() - entry.timestamp < this.maxAge) {
      return entry.addresses;
    }
    this.cache.delete(hostname);
    return null;
  }

  set(hostname, addresses) {
