  const cached = dnsCache.get(hostname);
  if (cached) {
    return cached[0]; // Return first cached IP
  }

  return new Promise((resolve, reject) => {
    dns.lookup(hostname, { all: true, family: 0 }, (err, addresses) => {
      if (err) {
