// Secure fetch with redirect following
async function secureFetch(urlString, requestId, redirectCount = 0) {
  if (redirectCount > config.maxRedirects) {
    throw new Error(`Maximum redirects (${config.maxRedirects}) exceeded`);
  }

  const { url, resolvedIP } = await validateAndResolveURL(urlString, requestId);
  const port = parseInt(url.port) || (url.protocol === 'https:' ? 443 : 80);

  return new Promise((resolve, reject) => {
    const options = {
      hostname: resolvedIP,
      port: port,
      path: url.pathname + url.search,
      method: 'GET',
      timeout: config.requestTimeout,
      headers: {
        'Host': url.hostname,
        'User-Agent': 'SecureWebhook/1.0',
        'Accept': 'application/json, text/plain, */*'
      },
      // Prevent Node from doing its own DNS lookup
      lookup: (hostname, opts, callback) => {
        callback(null, resolvedIP, net.isIPv6(resolvedIP) ? 6 : 4);
      },
      // Additional TLS validation for HTTPS
      rejectUnauthorized: true,
      checkServerIdentity: (servername, cert) => {
        // Verify certificate matches original hostname, not IP
        const validNames = [cert.subject?.CN, ...(cert.subjectaltname?.split(', ') || [])]
          .map(n => n?.replace('DNS:', ''));

        if (!validNames.some(n => n === url.hostname || 
            (n?.startsWith('*.') && url.hostname.endsWith(n.slice(1))))) {
          return new Error('Certificate hostname mismatch');
        }
      }
    };

    const client = url.protocol === 'https:' ? https : http;

    const req = client.request(options, (res) => {
      // Handle redirects securely
      if ([301, 302, 303, 307, 308].includes(res.statusCode)) {
        const location = res.headers.location;
        if (!location) {
          return reject(new Error('Redirect without Location header'));
        }

        // Resolve relative URLs
        let redirectUrl;
        try {
          redirectUrl = new URL(location, urlString).toString();
        } catch (e) {
          return reject(new Error('Invalid redirect URL'));
        }

        console.log(`[${requestId}] Redirect ${redirectCount + 1}: ${redirectUrl}`);

        // Recursively validate redirect target
        return secureFetch(redirectUrl, requestId, redirectCount + 1)
          .then(resolve)
          .catch(reject);
      }

      // Limit response size
      let data = '';
      let size = 0;

      res.on('data', chunk => {
        size += chunk.length;
        if (size > config.maxResponseSize) {
          req.destroy();
          return reject(new Error('Response too large'));
        }
        data += chunk;
      });

      res.on('end', () => {
        resolve({
          status: res.statusCode,
          headers: res.headers,
          data: data,
          finalUrl: urlString
        });
      });
    });

    req.on('error', (e) => {
      reject(new Error(`Request failed: ${e.message}`));
    });

    req.on('timeout', () => {
      req.destroy();
      reject(new Error('Request timeout'));
    });

    // Validate socket connection before sending
    req.on('socket', (socket) => {
      socket.on('connect', () => {
        const remoteIP = socket.remoteAddress;
        if (isBlockedIP(remoteIP)) {
          req.destroy();
          reject(new Error(`Connection to blocked IP: ${remoteIP}`));
        }
      });
    });

    req.end();
  });
}

