    // Rate limiting per source
    private final ConcurrentHashMap<String, RateLimiter> rateLimiters = new ConcurrentHashMap<>();

    private final HttpClient httpClient;
    private final DnsResolver customDnsResolver;

    public ProductionWebhookService() {
        this.customDnsResolver = new SecureDnsResolver();
        this.httpClient = HttpClient.newBuilder()
            .version(HttpClient.Version.HTTP_2)
            .connectTimeout(Duration.ofSeconds(5))
            .followRedirects(HttpClient.Redirect.NEVER)
            .build();
    }

    public WebhookResult fetchWebhook(String webhookUrl, String requesterId) 
            throws WebhookSecurityException {

        long startTime = System.currentTimeMillis();
        String requestId = generateRequestId();

        try {
            // Layer 1: Rate limiting
            if (!checkRateLimit(requesterId)) {
                securityLogger.warn("request_id={} requester={} action=RATE_LIMITED", 
                    requestId, requesterId);
                throw new WebhookSecurityException("Rate limit exceeded");
            }

            // Layer 2: URL parsing and scheme validation
            URL url = parseAndValidateUrl(webhookUrl);

            // Layer 3: Domain allowlist check (most restrictive)
            if (!isDomainAllowed(url.getHost())) {
                securityLogger.warn("request_id={} domain={} action=DOMAIN_BLOCKED",
                    requestId, url.getHost());
                throw new WebhookSecurityException("Domain not in allowlist");
            }

            // Layer 4: Secure DNS resolution with rebinding protection
            InetAddress[] resolvedAddresses = customDnsResolver.resolveWithProtection(
                url.getHost(), requestId);

            // Layer 5: Validate ALL resolved IPs (including IPv6)
            for (InetAddress addr : resolvedAddresses) {
                validateResolvedAddress(addr, url.getHost(), requestId);
            }

            // Layer 6: Make request with IP pinning
            InetAddress pinnedAddress = resolvedAddresses[0];
            String response = executeSecureRequest(url, pinnedAddress, requestId);

            // Layer 7: Response validation
            validateResponse(response, requestId);

            long duration = System.currentTimeMillis() - startTime;
            logger.info("request_id={} url={} duration_ms={} status=SUCCESS",
                requestId, sanitizeForLog(webhookUrl), duration);

            return new WebhookResult(true, response);

        } catch (WebhookSecurityException e) {
            throw e;
        } catch (Exception e) {
            securityLogger.error("request_id={} url={} error={}",
                requestId, sanitizeForLog(webhookUrl), e.getMessage());
            throw new WebhookSecurityException("Webhook fetch failed", e);
        }
    }

    private URL parseAndValidateUrl(String urlString) throws WebhookSecurityException {
        try {
            // Normalize URL to prevent encoding bypasses
            URI uri = new URI(urlString).normalize();
            URL url = uri.toURL();

            // Only HTTPS allowed
            if (!"https".equalsIgnoreCase(url.getProtocol())) {
                throw new WebhookSecurityException("Only HTTPS allowed");
            }

            // Block IP addresses directly in URL (force DNS resolution)
            String host = url.getHost();
            if (isIPAddress(host)) {
                throw new WebhookSecurityException("Direct IP addresses not allowed");
            }

            // Block suspicious URL patterns
            if (host.contains("@") || urlString.contains("%00")) {
                throw new WebhookSecurityException("Malformed URL detected");
            }

            // Validate port (only standard ports)
            int port = url.getPort();
            if (port != -1 && port != 443) {
                throw new WebhookSecurityException("Non-standard ports not allowed");
            }

            return url;
        } catch (Exception e) {
            throw new WebhookSecurityException("Invalid URL format");
        }
    }

    private void validateResolvedAddress(InetAddress addr, String hostname, String requestId) 
            throws WebhookSecurityException {

        String ip = addr.getHostAddress();

        // Check cloud metadata IPs
        if (METADATA_IPS.contains(ip)) {
            securityLogger.error(
                "request_id={} hostname={} resolved_ip={} action=METADATA_BLOCKED",
                requestId, hostname, ip);
            throw new WebhookSecurityException("Cloud metadata access blocked");
        }

        // Check reserved addresses using Java's built-in methods
        if (addr.isLoopbackAddress() ||
            addr.isLinkLocalAddress() ||
            addr.isSiteLocalAddress() ||
            addr.isAnyLocalAddress() ||
            addr.isMulticastAddress()) {

            securityLogger.error(
                "request_id={} hostname={} resolved_ip={} action=PRIVATE_IP_BLOCKED",
                requestId, hostname, ip);
            throw new WebhookSecurityException("Private/reserved IP blocked");
        }

        // IPv6-specific checks
        if (addr instanceof Inet6Address) {
            validateIPv6Address((Inet6Address) addr, hostname, requestId);
        }

        // Check for IPv4-mapped IPv6 addresses
        if (IPV6_LOCALHOST_PATTERN.matcher(ip).matches()) {
            securityLogger.error(
                "request_id={} hostname={} resolved_ip={} action=IPV6_LOCALHOST_BLOCKED",
                requestId, hostname, ip);
            throw new WebhookSecurityException("IPv6 localhost mapping blocked");
        }
    }

    private void validateIPv6Address(Inet6Address addr, String hostname, String requestId)
            throws WebhookSecurityException {

        String ip = addr.getHostAddress();

        // Block IPv6 unique local addresses (fc00::/7)
        byte[] addrBytes = addr.getAddress();
        if ((addrBytes[0] & 0xFE) == 0xFC) {
            securityLogger.error(
                "request_id={} hostname={} resolved_ip={} action=IPV6_ULA_BLOCKED",
                requestId, hostname, ip);
            throw new WebhookSecurityException("IPv6 unique local address blocked");
        }

        // Block IPv4-compatible IPv6 (deprecated but still exploitable)
        if (ip.contains(".")) {
            securityLogger.warn(
                "request_id={} hostname={} resolved_ip={} action=IPV4_COMPAT_DETECTED",
                requestId, hostname, ip);
            // Re-validate as IPv4
            try {
                String ipv4Part = ip.substring(ip.lastIndexOf(":") + 1);
                InetAddress ipv4Addr = InetAddress.getByName(ipv4Part);
                validateResolvedAddress(ipv4Addr, hostname, requestId);
            } catch (UnknownHostException e) {
                throw new WebhookSecurityException("Invalid IPv4-mapped address");
            }
        }
    }

    private String executeSecureRequest(URL url, InetAddress pinnedIP, String requestId)
            throws Exception {

        // Create URL with pinned IP but original host header
        int port = url.getPort() == -1 ? 443 : url.getPort();
        URI pinnedUri = new URI(
            url.getProtocol(),
            null,
            pinnedIP.getHostAddress(),
            port,
            url.getPath(),
            url.getQuery(),
            null
        );

        HttpRequest request = HttpRequest.newBuilder()
            .uri(pinnedUri)
            .header("Host", url.getHost())
            .header("User-Agent", "SecureWebhook/1.0")
            .header("X-Request-ID", requestId)
            .timeout(Duration.ofSeconds(10))
            .GET()
            .build();

        HttpResponse<String> response = httpClient.send(
            request, HttpResponse.BodyHandlers.ofString());

        // Validate response status
        int statusCode = response.statusCode();
        if (statusCode >= 300 && statusCode < 400) {
            securityLogger.warn(
                "request_id={} redirect_blocked location={}",
                requestId, response.headers().firstValue("Location").orElse("none"));
            throw new WebhookSecurityException("Redirects are not allowed");
        }

        if (statusCode != 200) {
            throw new WebhookSecurityException("Unexpected response code: " + statusCode);
        }

        return response.body();
    }

    private boolean isIPAddress(String host) {
        try {
            // Check for IPv4
            if (Pattern.matches("\\d+\\.\\d+\\.\\d+\\.\\d+", host)) {
                return true;
            }
            // Check for IPv6 (contains colons)
            if (host.contains(":")) {
                return true;
            }
            // Check for decimal/octal/hex IP representations
            if (Pattern.matches("^\\d+$", host) || 
                Pattern.matches("^0[xX][0-9a-fA-F]+$", host)) {
                return true;
            }
            return false;
        } catch (Exception e) {
            return false;
        }
    }

    // Nested class for secure DNS resolution
    private static class SecureDnsResolver {
        private final ConcurrentHashMap<String, CachedResolution> cache = 
            new ConcurrentHashMap<>();
        private static final long CACHE_TTL_MS = 60000; // 1 minute

        public InetAddress[] resolveWithProtection(String hostname, String requestId)
                throws WebhookSecurityException {
            try {
                // Check cache first (prevents rebinding between calls)
                CachedResolution cached = cache.get(hostname);
                if (cached != null && !cached.isExpired()) {
                    return cached.addresses;
                }

                // Resolve all addresses (IPv4 and IPv6)
                InetAddress[] addresses = InetAddress.getAllByName(hostname);

                if (addresses.length == 0) {
                    throw new WebhookSecurityException("No addresses resolved");
                }

                // Cache the resolution
                cache.put(hostname, new CachedResolution(addresses));

                return addresses;
            } catch (UnknownHostException e) {
                throw new WebhookSecurityException("DNS resolution failed");
            }
        }

        private static class CachedResolution {
            final InetAddress[] addresses;
            final long timestamp;

            CachedResolution(InetAddress[] addresses) {
                this.addresses = addresses;
                this.timestamp = System.currentTimeMillis();
            }

            boolean isExpired() {
                return System.currentTimeMillis() - timestamp > CACHE_TTL_MS;
            }
        }
    }

    // Helper methods
    private boolean checkRateLimit(String requesterId) {
        // Implementation with sliding window rate limiter
        return true; // Simplified
    }

    private boolean isDomainAllowed(String domain) {
        return ALLOWED_DOMAINS.contains(domain.toLowerCase());
    }

    private void validateResponse(String response, String requestId) {
        // Check response size, content type, etc.
    }

    private String generateRequestId() {
        return java.util.UUID.randomUUID().toString();
    }

    private String sanitizeForLog(String input) {
        return input.replaceAll("[\\r\\n]", "_").substring(0, Math.min(100, input.length()));
    }
}

