// SECURE: Custom dialer that validates IP at connection time
func safeDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve DNS ourselves
	ips, err := net.DefaultResolver.LookupIP(ctx, "ip", host)
	if err != nil {
		return nil, err
	}

	for _, ip := range ips {
		// Check each resolved IP against blocklist
		for _, blocked := range blockedCIDRs {
			if blocked.Contains(ip) {
				return nil, fmt.Errorf("blocked IP address: %s", ip)
			}
		}
	}

	// Connect directly to the validated IP (no second DNS lookup)
	var dialer net.Dialer
	for _, ip := range ips {
		conn, err := dialer.DialContext(ctx, network, net.JoinHostPort(ip.String(), port))
		if err == nil {
			return conn, nil
		}
	}

	return nil, errors.New("failed to connect to any resolved IP")
}

