Excellent question! Attackers use numerous IP representation tricks to bypass naive string-based filters. Examples include decimal IPs (2130706433 = 127.0.0.1), octal (0177.0.0.1), IPv4-mapped IPv6 (::ffff:127.0.0.1), and URL encoding. You need robust IP parsing that handles all representations.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/tls"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"net"
	"net/http"
	"net/url"
	"os"
	"regexp"
	"strings"
	"time"
)

type SSRFProtector struct {
	blockedCIDRs   []*net.IPNet
	allowedDomains map[string]bool
	logger         *slog.Logger
	client         *http.Client
}

func NewSSRFProtector(allowedDomains []string) *SSRFProtector {
	p := &SSRFProtector{
		allowedDomains: make(map[string]bool),
		logger:         slog.New(slog.NewJSONHandler(os.Stdout, nil)),
	}

	// Comprehensive blocklist including cloud metadata endpoints
	blocked := []string{
		// IPv4 private and special ranges
		"0.0.0.0/8",         // "This" network
		"10.0.0.0/8",        // Private
		"100.64.0.0/10",     // Carrier-grade NAT
		"127.0.0.0/8",       // Loopback
		"169.254.0.0/16",    // Link-local (AWS/Azure/GCP metadata)
		"172.16.0.0/12",     // Private
		"192.0.0.0/24",      // IETF protocol assignments
		"192.0.2.0/24",      // TEST-NET-1
		"192.88.99.0/24",    // 6to4 relay
		"192.168.0.0/16",    // Private
		"198.18.0.0/15",     // Benchmark testing
		"198.51.100.0/24",   // TEST-NET-2
		"203.0.113.0/24",    // TEST-NET-3
		"224.0.0.0/4",       // Multicast
		"240.0.0.0/4",       // Reserved
		"255.255.255.255/32", // Broadcast
		// IPv6 ranges
		"::1/128",           // Loopback
		"::/128",            // Unspecified
		"::ffff:0:0/96",     // IPv4-mapped (CRITICAL for bypasses)
		"64:ff9b::/96",      // NAT64
		"100::/64",          // Discard
		"fc00::/7",          // Unique local
		"fe80::/10",         // Link-local
		"ff00::/8",          // Multicast
	}

	for _, cidr := range blocked {
		_, network, err := net.ParseCIDR(cidr)
		if err == nil {
			p.blockedCIDRs = append(p.blockedCIDRs, network)
		}
	}

	for _, domain := range allowedDomains {
		p.allowedDomains[strings.ToLower(domain)] = true
	}

	p.client = p.createSecureClient()
	return p
}

// Normalize IP handles various representation attacks
func (p *SSRFProtector) normalizeAndValidateIP(ip net.IP) (net.IP, error) {
	if ip == nil {
		return nil, errors.New("nil IP address")
	}

	// Convert IPv4-mapped IPv6 to IPv4 for consistent checking
	if ip4 := ip.To4(); ip4 != nil {
		ip = ip4
	}

	// Check against all blocked ranges
	for _, blocked := range p.blockedCIDRs {
		if blocked.Contains(ip) {
			return nil, fmt.Errorf("IP %s is in blocked range %s", ip, blocked)
		}
	}

	// Additional checks for edge cases
	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() ||
		ip.IsLinkLocalMulticast() || ip.IsMulticast() || ip.IsUnspecified() {
		return nil, fmt.Errorf("IP %s is a special address", ip)
	}

	return ip, nil
}

// Validate URL before any network operation
func (p *SSRFProtector) validateURL(rawURL string) (*url.URL, error) {
	// Parse URL
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return nil, fmt.Errorf("invalid URL: %w", err)
	}

	// Only allow http/https
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, errors.New("only http and https schemes allowed")
	}

	// Reject URLs with credentials
	if parsedURL.User != nil {
		return nil, errors.New("URLs with credentials not allowed")
	}

	// Block suspicious hostname patterns (decimal, octal, hex IPs)
	hostname := parsedURL.Hostname()

	// Check for numeric IP representations that bypass string filters
	suspiciousPatterns := []*regexp.Regexp{
		regexp.MustCompile(`^\d+$`),                    // Decimal IP: 2130706433
		regexp.MustCompile(`^0[0-7]+`),                  // Octal: 0177.0.0.1
		regexp.MustCompile(`^0x[0-9a-fA-F]+`),           // Hex: 0x7f000001
		regexp.MustCompile(`%[0-9a-fA-F]{2}`),           // URL encoded
	}

	for _, pattern := range suspiciousPatterns {
		if pattern.MatchString(hostname) {
			// Parse it anyway and validate the resulting IP
			ip := net.ParseIP(hostname)
			if ip != nil {
				if _, err := p.normalizeAndValidateIP(ip); err != nil {
					return nil, fmt.Errorf("suspicious hostname resolves to blocked IP: %w", err)
				}
			}
		}
	}

	// If using domain allowlist, check it
	if len(p.allowedDomains) > 0 {
		lowerHost := strings.ToLower(hostname)
		allowed := false
		for domain := range p.allowedDomains {
			if lowerHost == domain || strings.HasSuffix(lowerHost, "."+domain) {
				allowed = true
				break
			}
		}
		if !allowed {
			return nil, fmt.Errorf("domain %s not in allowlist", hostname)
		}
	}

	return parsedURL, nil
}

// Safe dialer with atomic DNS resolution and IP validation
func (p *SSRFProtector) safeDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}

	// Resolve DNS with timeout
	resolveCtx, cancel := context.WithTimeout(ctx, 5*time.Second)
	defer cancel()

	ips, err := net.DefaultResolver.LookupIP(resolveCtx, "ip", host)
	if err != nil {
		p.logger.Warn("DNS resolution failed",
			"host", host,
			"error", err.Error())
		return nil, fmt.Errorf("DNS resolution failed: %w", err)
	}

	var validIPs []net.IP
	for _, ip := range ips {
		normalizedIP, err := p.normalizeAndValidateIP(ip)
		if err != nil {
			p.logger.Warn("Blocked IP in DNS response",
				"host", host,
				"ip", ip.String(),
				"reason", err.Error())
			continue
		}
		validIPs = append(validIPs, normalizedIP)
	}

	if len(validIPs) == 0 {
		p.logger.Error("All resolved IPs blocked - possible DNS rebinding attack",
			"host", host,
			"resolved_ips", fmt.Sprintf("%v", ips))
		return nil, errors.New("no valid IPs available - all blocked")
	}

	// Connect directly to validated IP
	var dialer net.Dialer
	dialer.Timeout = 10 * time.Second

	var lastErr error
	for _, ip := range validIPs {
		ipAddr := net.JoinHostPort(ip.String(), port)
		conn, err := dialer.DialContext(ctx, network, ipAddr)
		if err != nil {
			lastErr = err
			continue
		}

		p.logger.Info("Outbound connection established",
			"host", host,
			"connected_ip", ip.String())
		return conn, nil
	}

	return nil, fmt.Errorf("failed to connect: %w", lastErr)
}

func (p *SSRFProtector) createSecureClient() *http.Client {
	return &http.Client{
		Timeout: 30 * time.Second,
		Transport: &http.Transport{
			DialContext:           p.safeDialContext,
			ForceAttemptHTTP2:     false,
			MaxIdleConns:          10,
			IdleConnTimeout:       30 * time.Second,
			TLSHandshakeTimeout:   10 * time.Second,
			ResponseHeaderTimeout: 10 * time.Second,
			DisableKeepAlives:     true,
			TLSClientConfig: &tls.Config{
				MinVersion: tls.VersionTLS12,
			},
		},
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 5 {
				return errors.New("stopped after 5 redirects")
			}
			// Re-validate each redirect URL
			return nil
		},
	}
}

func (p *SSRFProtector) Fetch(ctx context.Context, rawURL string) ([]byte, error) {
	// Pre-request URL validation
	parsedURL, err := p.validateURL(rawURL)
	if err != nil {
		p.logger.Warn("URL validation failed",
			"url", rawURL,
			"error", err.Error())
		return nil, fmt.Errorf("URL validation failed: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, "GET", parsedURL.String(), nil)
	if err != nil {
		return nil, err
	}

	req.Header.Set("User-Agent", "WebhookFetcher/1.0")

	resp, err := p.client.Do(req)
	if err != nil {
		p.logger.Warn("Request failed",
			"url", parsedURL.String(),
			"error", err.Error())
		return nil, err
	}
	defer resp.Body.Close()

	// Limit response size to prevent DoS
	limitedReader := io.LimitReader(resp.Body, 5*1024*1024) // 5MB
	body, err := io.ReadAll(limitedReader)
	if err != nil {
		return nil, err
	}

	p.logger.Info("Request completed",
		"url", parsedURL.String(),
		"status", resp.StatusCode,
		"size", len(body))

	return body, nil
}

func webhookHandler(protector *SSRFProtector) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		var req struct {
			URL string `json:"url"`
		}

		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			http.Error(w, `{"error": "invalid request"}`, http.StatusBadRequest)
			return
		}

		ctx, cancel := context.WithTimeout(r.Context(), 30*time.Second)
		defer cancel()

		body, err := protector.Fetch(ctx, req.URL)
		if err != nil {
			http.Error(w, `{"error": "fetch failed"}`, http.StatusForbidden)
			return
		}

		w.Header().Set("Content-Type", "application/octet-stream")
		w.Write(body)
	}
}

func main() {
	// Production: Use domain allowlist for maximum security
	allowedDomains := []string{"api.github.com", "api.stripe.com"}
	protector := NewSSRFProtector(allowedDomains)

	http.HandleFunc("/webhook", webhookHandler(protector))
	http.ListenAndServe(":8080", nil)
}
